  ('immigration-1aab856d-moex-00470', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '員警因線報得知甲涉嫌販毒，乃聲請搜索其住宅之搜索票，但於現場未發現可疑物品。然過程中 發現甲或將違法物品藏於同棟大樓不同樓層其母乙家中，遂以涉及賭博為由進入乙之住宅，並於 其內房間發現毒品及吸食器。試問有關查扣毒品吸食器之證據能力，下列敘述何者正確？', '["依刑事訴訟法第128條規定不該當搜索範圍無證據能力", "依刑事訴訟法第131條規定該當附帶搜索有證據能力", "依刑事訴訟法第132條規定該當逕行搜索有證據能力", "依刑事訴訟法第137條規定該當另案搜索有證據能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00471', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '有關刑事訴訟法第154條「無罪推定」之規定，下列敘述何者正確？', '["對被告的不利事證，檢察官有舉證責任", "對被告的有利事證，被告有舉證責任", "對被告的不利事證，法官有舉證責任", "對被告的有利事證，應達到無容懷疑程度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00472', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲對於某飲食店服務態度不佳心生怨憤，寄信恐嚇稱：「不付錢解決，生意不要做了。」若此封信 件提出法庭證明恐嚇行為，下列敘述何者正確？', '["屬自白證據，有證據能力", "屬非傳聞證據，有證據能力", "屬傳聞證據，無證據能力", "屬傳聞例外，有證據能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00473', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '員警實施通訊監察得知毒販甲即將進行毒品交易，現為掌握毒販甲之交易對象、狀況等，於甲汽 車底盤裝置全球衛星定位系統（GPS），追蹤其於公有道路之行車路徑。員警裝設 GPS 進行偵查 蒐證，依現行實務見解，下列敘述何者正確？', '["屬於任意處分", "適用通訊保障法", "應經檢察官核發令狀", "應有法律明文授權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00474', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '犯罪偵查階段檢察官聲請羈押犯罪嫌疑人，下列敘述何者正確？', '["犯罪嫌疑應屬重大犯罪", "犯罪嫌疑之認定適用傳聞法則", "犯罪嫌疑的證明應以適當之方法使被告獲知卷證內容", "犯罪嫌疑的證明應無容合理懷疑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00475', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲因A欠錢不還，以強酸液體潑灑A，致其視力嚴重受損，檢察官以重傷罪提起公訴。A經法院 同意參與訴訟，關於A於審理過程得以實施的訴訟權利，下列敘述何者正確？', '["詰問證人", "聲請調查證據", "詰問被告", "就證據調查表示意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00476', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'essay', '甲有一筆閒置之山坡地，某日颱風過後經暴雨沖刷露出大量廢棄物。主
管機關勘驗後，依廢棄物清理法第 71 條第 1 項規定，以 A 函通知甲限
期於三個月內自行清除。請問：
甲不服 A函而提起行政救濟，主張命其限期清除處理為行政罰。惟依
廢棄物品內容之客觀事證觀之，違規事實之發生早已逾行政罰法第 27
條規定之三年裁處權時效，甲之主張有無理由？（15分）
甲因屆期不為清除處理，主管機關遂代為清除、處理，並以 B函向甲
求償清理、改善及衍生之必要費用。甲屆期未清償前述必要費用，主
管機關移送行政執行，行政執行機關以 C函通知甲應於一個月清償完
畢或協商分期清償，否則屆時將向行政法院聲請假扣押甲之土地。甲
不服 C函，應如何提起行政救濟？（10 分）
附：廢棄物清理法第 71條第 1項規定：「不依規定清除、處理之廢棄物，
直轄市、縣（市）主管機關或執行機關得命事業、受託清除處理廢棄
物者、仲介非法清除處理廢棄物者、容許或因重大過失致廢棄物遭
非法棄置於其土地之土地所有人、管理人或使用人，限期清除處理。
屆期不為清除處理時，直轄市、縣（市）主管機關或執行機關得代為
清除、處理，並向其求償清理、改善及衍生之必要費用。屆期未清償
者，移送強制執行；直轄市、縣（市）主管機關或執行機關得免提供
擔保向行政法院聲請假扣押、假處分」。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "ee3f88193c9a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00477', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'essay', '甲市政府為傳染病疫情防治需要，公告全市餐廳一律禁止內用，僅得外
